func:
// Stocker la temperature ambiante dans le contexte flow
var data = msg.payload;
flow.set('T_ambiante', data.temperature || 25);
flow.set('humidite', data.humidite || 50);
return msg;

// Extraire le numero de pompe du topic
// Topic format: station/pompe/X/pt100/avant/temperature
var parts = msg.topic.split('/');
var pompeNum = parseInt(parts[2]);
var pompeId = 'pompe_' + pompeNum;

var T_moteur = msg.payload.temperature;
var T_ambiante = flow.get('T_ambiante') || 25;
var humidite = flow.get('humidite') || 50;

// --- Calcul Delta T ---
var delta_T = Math.max(0, T_moteur - T_ambiante);

// --- Calcul Pente (variation par minute) ---
var historique = flow.get('historique_' + pompeId) || [];
historique.push({ delta_T: delta_T, timestamp: Date.now() });

// Garder 60 derniers points (2 minutes a 2s d'intervalle)
if (historique.length > 60) historique.shift();
flow.set('historique_' + pompeId, historique);

var pente = 0;
if (historique.length >= 2) {
    var ancien = historique[0];
    var recent = historique[historique.length - 1];
    var dureeMin = (recent.timestamp - ancien.timestamp) / 60000;
    if (dureeMin > 0) {
        pente = (recent.delta_T - ancien.delta_T) / dureeMin;
    }
}

// --- Calcul Health Score (par paliers) ---
var health_score = 100;
if (delta_T <= 15) {
    health_score = 100;
} else if (delta_T <= 30) {
    health_score = 100 - ((delta_T - 15) / 15) * 20;
} else if (delta_T <= 45) {
    health_score = 80 - ((delta_T - 30) / 15) * 30;
} else if (delta_T <= 60) {
    health_score = 50 - ((delta_T - 45) / 15) * 30;
} else {
    health_score = Math.max(0, 20 - ((delta_T - 60) / 20) * 20);
}

// Penalite pente
if (pente > 0.5) {
    health_score -= (pente - 0.5) * 10;
}
health_score = Math.max(0, Math.min(100, Math.round(health_score)));

// --- Calcul RUL ---
var seuil_critique = 70;
var rul_minutes = -1;
if (pente > 0.1) {
    rul_minutes = Math.round((seuil_critique - delta_T) / pente);
    if (rul_minutes < 0) rul_minutes = 0;
}

// --- Stocker dans le contexte flow pour l'API ---
var pompesData = flow.get('pompes_data') || {};
pompesData[pompeId] = {
    pompe_id: pompeId,
    T_moteur: Math.round(T_moteur * 100) / 100,
    T_ambiante: Math.round(T_ambiante * 100) / 100,
    delta_T: Math.round(delta_T * 100) / 100,
    health_score: health_score,
    pente: Math.round(pente * 1000) / 1000,
    rul_minutes: rul_minutes,
    humidite: humidite,
    timestamp: new Date().toISOString()
};
flow.set('pompes_data', pompesData);

// Sortie pour InfluxDB
msg.payload = {
    T_moteur: T_moteur,
    T_ambiante: T_ambiante,
    delta_T: delta_T,
    health_score: health_score,
    pente: pente,
    rul_minutes: rul_minutes
};
msg.measurement = 'pt100_data';
msg.tags = { pompe_id: pompeId };
msg.pompe_id = pompeId;

return msg;

var pompesData = flow.get('pompes_data') || {};
var T_ambiante = flow.get('T_ambiante') || 25;
var humidite = flow.get('humidite') || 50;

// Verifier s'il y a des donnees
var hasDonnees = Object.keys(pompesData).length > 0;

if (!hasDonnees) {
    msg.payload = {
        status: 'ok',
        message: 'En attente des premieres donnees...',
        pompes: {
            pompe_1: { T_moteur: null, T_ambiante: T_ambiante, delta_T: null, health_score: null, pente: null, rul_minutes: null, humidite: humidite },
            pompe_2: { T_moteur: null, T_ambiante: T_ambiante, delta_T: null, health_score: null, pente: null, rul_minutes: null, humidite: humidite },
            pompe_3: { T_moteur: null, T_ambiante: T_ambiante, delta_T: null, health_score: null, pente: null, rul_minutes: null, humidite: humidite },
            pompe_4: { T_moteur: null, T_ambiante: T_ambiante, delta_T: null, health_score: null, pente: null, rul_minutes: null, humidite: humidite },
            pompe_5: { T_moteur: null, T_ambiante: T_ambiante, delta_T: null, health_score: null, pente: null, rul_minutes: null, humidite: humidite }
        },
        timestamp: new Date().toISOString()
    };
    msg.headers = { 'Access-Control-Allow-Origin': '*' };
    return msg;
}

msg.payload = {
    status: 'ok',
    pompes: pompesData,
    T_ambiante: T_ambiante,
    humidite: humidite,
    timestamp: new Date().toISOString()
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

var predictions = flow.get('ml_predictions') || {};
var mlActive = Object.keys(predictions).length > 0;

var result = {
    ml_active: mlActive,
    predictions: {}
};

for (var i = 1; i <= 5; i++) {
    var key = 'pompe_' + i;
    var pred = predictions[i] || predictions[key] || null;

    if (pred) {
        result.predictions[key] = {
            score_anomalie: pred.isolation_forest ? pred.isolation_forest.score_anomalie : 0,
            est_anomalie: pred.isolation_forest ? pred.isolation_forest.est_anomalie : false,
            delta_t_predit: pred.lstm ? pred.lstm.delta_t_predit : null,
            health_predit: pred.lstm ? pred.lstm.health_predit : null,
            rul_predit: pred.lstm ? pred.lstm.rul_minutes : -1,
            tendance: pred.lstm ? pred.lstm.tendance : 0,
            niveau_ml: pred.niveau_ml || 'NORMAL',
            confiance: pred.confiance || 0
        };
    } else {
        result.predictions[key] = {
            score_anomalie: 0,
            est_anomalie: false,
            delta_t_predit: null,
            health_predit: null,
            rul_predit: -1,
            tendance: 0,
            niveau_ml: 'NORMAL',
            confiance: 0
        };
    }
}

msg.payload = result;
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type'
};
msg.payload = '';
msg.statusCode = 204;
return msg;
